1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	}
5	
6	interface Customer {
7	  yearsWithMHPCO: number;
8	  contractCount: number;
9	}
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	};
18	
19	const BLOCK_PRICE_FOR_3_ALIKE = 60;
20	
21	export function generateQuote(items: Item[], customer: Customer): { basePremium: number } {
22	  const nonCursedCountsByType: Record<string, number> = {};
23	  let cursedPremium = 0;
24	
25	  for (const item of items) {
26	    if (item.cursed) {
27	      cursedPremium += BASE_PREMIUMS[item.type] * 1.5;
28	    } else {
29	      nonCursedCountsByType[item.type] = (nonCursedCountsByType[item.type] ?? 0) + 1;
30	    }
31	  }
32	
33	  let basePremium = cursedPremium;
34	  for (const [type, count] of Object.entries(nonCursedCountsByType)) {
35	    if (count === 3) {
36	      basePremium += BLOCK_PRICE_FOR_3_ALIKE;
37	    } else {
38	      basePremium += count * BASE_PREMIUMS[type];
39	    }
40	  }
41	
42	  return { basePremium };
43	}
